package com.museumheist.game.entity;
public class Laser { private final float startX,startY,endX,endY,period,activeSeconds,phase; public Laser(float sx,float sy,float ex,float ey,float period,float activeSeconds,float phase){startX=sx;startY=sy;endX=ex;endY=ey;this.period=Math.max(.1f,period);this.activeSeconds=Math.max(0,activeSeconds);this.phase=phase;} public float getStartX(){return startX;} public float getStartY(){return startY;} public float getEndX(){return endX;} public float getEndY(){return endY;} public boolean isActive(float elapsed){float t=(elapsed+phase)%period; if(t<0)t+=period; return t<activeSeconds;} }
